import{_ as e,o as d,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt6102.jpg",i="/images/lekt6106.jpg",o="/images/lekt6107.jpg",l="/images/lekt6104.jpg",u="/images/lekt6105.jpg",s="/images/lekt6103.jpg",h="/images/lekt6109.jpg",m="/images/lekt6110.jpg",b="/images/lekt6111.jpg",p="/images/lekt6113.jpg",c="/images/lekt6112.jpg",g="/images/lekt6114.jpg",k="/images/lekt6115.jpg",f="/images/lekt6118.jpg",q="/images/lekt6116.jpg",w="/images/lekt6117.jpg",v="/images/lekt6101.jpg",z="/images/lekt6119.jpg",K=JSON.parse('{"title":"Lektion 61","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion61.md","filePath":"lektionen/lektion61.md"}'),y={name:"lektionen/lektion61.md"};function _(P,t,B,x,S,N){return d(),a("div",null,[...t[0]||(t[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-61" tabindex="-1">Lektion 61 <a class="header-anchor" href="#lektion-61" aria-label="Permalink to &quot;Lektion 61&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>61.1. Deklination der Wurzelnomina auf -ā, -ī, -ū <ul><li>61.1.1. Wurzelnomina auf -ā am Ende von तत्पुरुष</li><li>61.1.2. Feminine Wurzelnomina auf -ī</li><li>61.1.3. Wurzelnomina auf -ī am Ende von तत्पुरुष</li><li>61.1.4. Einsilbige, feminine Wurzelnomina auf -ū</li><li>61.1.5. Wurzelnomina auf -ū am Ende von तत्पुरुष</li><li>61.1.6. Deklination mehrsilbiger Feminina auf -ū</li></ul></li><li>61.2. Das periphrastische Futur (लुट्)</li><li>61.3. Das Intensivum (Frequentativum) (चर्करीतम्) <ul><li>61.3.1. Ātmanepada-Intensivum</li><li>61.3.2. Parasmaipada-Intensivum</li></ul></li><li>61.4. Denominativa (नामधातु) <ul><li>61.4.1. Bildung ohne besonderes Suffix, Parasmaipada</li><li>61.4.2. Bildung mit Suffix -ya, Parasmaipada</li><li>61.4.3. Bildung mit dem Suffix -kāmya, Parasmaipada</li><li>61.4.4. Bildung mit dem Suffix -sya oder -asya, Parasmaipada</li><li>61.4.5. Bildung mit dem Suffix -ya, Ātmanepada</li><li>61.4.6. Bildung mit dem Suffix -aya, -āpaya</li></ul></li><li>61.5. Der Benediktiv (आशीर्लिङ्)</li><li>61.6. Der Konditionalis (ऌङ्)</li><li>61.7. Deklination der Nomina auf -ai, -o, -au</li><li>61.8. Restliche Pronomina <ul><li>61.8.1. Personalpronomen des Dual</li><li>61.8.2. Demonstrativpronomen अदस् &quot;jener (entfernte)&quot;</li></ul></li><li>61.9. Entlassung in den Ozean der Sanskritliteratur: ಶ್ರೀಗಣನಾಥ / श्रीगणनाथ</li></ul><h2 id="_61-1-deklination-der-wurzelnomina-auf-a-i-u" tabindex="-1">61.1. Deklination der Wurzelnomina auf -ā, -ī, -ū <a class="header-anchor" href="#_61-1-deklination-der-wurzelnomina-auf-a-i-u" aria-label="Permalink to &quot;61.1. Deklination der Wurzelnomina auf -ā, -ī, -ū&quot;">​</a></h2><h3 id="_61-1-1-wurzelnomina-auf-a-am-ende-von-तत्पुरुष" tabindex="-1">61.1.1. Wurzelnomina auf -ā am Ende von तत्पुरुष <a class="header-anchor" href="#_61-1-1-wurzelnomina-auf-a-am-ende-von-तत्पुरुष" aria-label="Permalink to &quot;61.1.1. Wurzelnomina auf -ā am Ende von तत्पुरुष&quot;">​</a></h3><p>Vor vokalischen Endungen hat der Stammvokal in den schwachen Kasus die Schwundstufe Ø.</p><p>Die Deklination im Maskulinum und Femininum ist identisch.</p><p>Paradigma:</p><p>विश्वपा m.f. &quot;das All beschützend&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा /</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>विश्वपास्</td><td>विश्वपौ</td><td>विश्वपास्</td></tr><tr><td>द्वितीया</td><td>विश्वपाम्</td><td>विश्वपस्</td><td></td></tr><tr><td>तृतीया</td><td>विश्वपा</td><td>विश्वपाभ्याम्</td><td>विश्वपाभस्</td></tr><tr><td>चतुर्थी</td><td>विश्वपे</td><td>विश्वपाभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>विश्वपस्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>विश्वपोस्</td><td>विश्वपाम्</td><td></td></tr><tr><td>सप्तमी</td><td>विश्वपि</td><td>विश्वपासु</td><td></td></tr></tbody></table></blockquote><h3 id="_61-1-2-feminine-wurzelnomina-auf-i" tabindex="-1">61.1.2. Feminine Wurzelnomina auf -ī <a class="header-anchor" href="#_61-1-2-feminine-wurzelnomina-auf-i" aria-label="Permalink to &quot;61.1.2. Feminine Wurzelnomina auf -ī&quot;">​</a></h3><p>Vor vokalischer Endung wird -ī durch -iy ersetzt.</p><p>Neben den Bildungen mit den regulären Kasusendungen kommen im Dat.Ab.Gen.Lok.sg. und Gen.pl. auch Bildungen nach dem Muster mehrsilbiger Feminina auf -ī (देवी) vor.</p><p>Paradigma:</p><p>धी f. &quot;Gedanke&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा /</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>धीस्</td><td>धियौ</td><td>धियस्</td></tr><tr><td>द्वितीया</td><td>धियम्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>धिया</td><td>धीभ्याम्</td><td>धीभिस्</td></tr><tr><td>चतुर्थी</td><td>धिये  /  धियै</td><td>धीभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>धियस्  /  धिया्स्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>धियोस्</td><td>धियाम्  / धीनाम्</td><td></td></tr><tr><td>सप्तमी</td><td>धियि  / धियाम्</td><td>धीषु</td><td></td></tr></tbody></table></blockquote><p>Unregelmäßig: स्त्री  f. &quot;Frau&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>स्त्री</td><td>स्त्रियौ</td><td>स्त्रियस्</td></tr><tr><td>द्वितीया</td><td>स्त्रियम्  / स्त्रीम्</td><td>स्त्रियस्  / स्त्रीस्</td><td></td></tr><tr><td>तृतीया</td><td>स्त्रिया</td><td>स्त्रीभ्याम्</td><td>स्त्रीभिस्</td></tr><tr><td>चतुर्थी</td><td>स्त्रियै</td><td>स्त्रीभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>स्त्रियास्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>स्त्रियोस्</td><td>स्त्रीणाम्</td><td></td></tr><tr><td>सप्तमी</td><td>स्त्रियाम्</td><td>स्त्रीषु</td><td></td></tr><tr><td>आमन्त्रितम्</td><td>स्त्रि</td><td>स्त्रियौ</td><td>स्त्रियस्</td></tr></tbody></table></blockquote><p><img src="'+n+'" alt=""><br> Abb.: स्त्रियः<br> [Bildquelle: World Bank / Curt Carnemark. -- <a href="http://www.flickr.com/photos/worldbank/2241690863/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2241690863/</a>. -- Zugriff am 2009-03-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h3 id="_61-1-3-wurzelnomina-auf-i-am-ende-von-तत्पुरुष" tabindex="-1">61.1.3. Wurzelnomina auf -ī am Ende von तत्पुरुष <a class="header-anchor" href="#_61-1-3-wurzelnomina-auf-i-am-ende-von-तत्पुरुष" aria-label="Permalink to &quot;61.1.3. Wurzelnomina auf -ī am Ende von तत्पुरुष&quot;">​</a></h3><p>Vor vokalischen Endungen wird -ī durch -y ersetzt, wenn ihm nur ein zur Wurzel gehörender Konsonant vorausgeht. Gehen mehrere zur Wurzel gehörende Konsonanten voraus, wird das -ī vor vokalischer Endung durch -iy ersetzt.</p><p>Die Deklination ist im Maskulinum und Femininum identisch.</p><p>Unregelmäßigkeit: Komposita auf -नी &quot;führend&quot; haben im Lok.sg die Endung -ām (wie देवी):<br> z.B. ग्रामणी &quot;eine Schar/ein Dorf führend&quot;: Lok.sg.m.f. ग्रामण्याम्</p><p>Paradigmen:</p><p>शुद्धधी m., f. &quot;Reines denkend&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा /</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>शुद्धधीस्</td><td>शुद्धध्यौ</td><td>शुद्धध्यस्</td></tr><tr><td>द्वितीया</td><td>शुद्धध्यम्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>शुद्धध्या</td><td>शुद्धधीभ्याम्</td><td>शुद्धधीभिस्</td></tr><tr><td>चतुर्थी</td><td>शुद्धध्ये</td><td>शुद्धधीभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>शुद्धध्यस्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>शुद्धध्योस्</td><td>शुद्धध्याम्</td><td></td></tr><tr><td>सप्तमी</td><td>शुद्धध्यि</td><td>शुद्धधीषु</td><td></td></tr></tbody></table></blockquote><p>यवक्री m., f. &quot;Gerste kaufend&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा /</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>यवक्रीस्</td><td>यवक्रियौ</td><td>यवक्रियस्</td></tr><tr><td>द्वितीया</td><td>यवक्रियम्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>यवक्रिया</td><td>यवक्रीभ्याम्</td><td>यवक्रीभिस्</td></tr><tr><td>चतुर्थी</td><td>यवक्रिये</td><td>यवक्रीभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>यवक्रियस्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>यवक्रियोस्</td><td>यवक्रियाम्</td><td></td></tr><tr><td>सप्तमी</td><td>यवक्रियि</td><td>यवक्रीषु</td><td></td></tr></tbody></table></blockquote><h3 id="_61-1-4-einsilbige-feminine-wurzelnomina-auf-u" tabindex="-1">61.1.4. Einsilbige, feminine Wurzelnomina auf -ū <a class="header-anchor" href="#_61-1-4-einsilbige-feminine-wurzelnomina-auf-u" aria-label="Permalink to &quot;61.1.4. Einsilbige, feminine Wurzelnomina auf -ū&quot;">​</a></h3><p>Stamm vor Vokal: -uv</p><p>Deklination analog zu den femininen Wurzelnomina auf -ī</p><p>Paradigma:</p><p>भू f. &quot;Erde&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा /</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>भूस्</td><td>भुवौ</td><td>भुवस्</td></tr><tr><td>द्वितीया</td><td>भुवम्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>भुवा</td><td>भूभ्याम्</td><td>भूभिस्</td></tr><tr><td>चतुर्थी</td><td>भुवे / भुवै</td><td>भूभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>भुवस् / भुवास्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>भुवोस्</td><td>भुवाम्</td><td></td></tr><tr><td>सप्तमी</td><td>भुवि / भुवाम्</td><td>भूषु</td><td></td></tr></tbody></table></blockquote><h3 id="_61-1-5-wurzelnomina-auf-u-am-ende-von-तत्पुरुष" tabindex="-1">61.1.5. Wurzelnomina auf -ū am Ende von तत्पुरुष <a class="header-anchor" href="#_61-1-5-wurzelnomina-auf-u-am-ende-von-तत्पुरुष" aria-label="Permalink to &quot;61.1.5. Wurzelnomina auf -ū am Ende von तत्पुरुष&quot;">​</a></h3><p>Vor vokalischen Endungen wird -ū durch -v ersetzt, wenn ihm nur ein zur Wurzel gehörender Konsonant vorausgeht. Gehen mehrere zur Wurzel gehörende Konsonanten voraus, wird das -ū vor vokalischer Endung durch -uv ersetzt.</p><p>Die Deklination ist im Maskulinum und Femininum identisch.</p><p>Paradigma:</p><p>खलपू m., f. &quot;die Scheune kehrend&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा /</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>खलपूस्</td><td>खलप्वौ</td><td>खलप्वस्</td></tr><tr><td>द्वितीया</td><td>खलप्वम्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>खलप्वा</td><td>खलपूभ्याम्</td><td>खलपूभिस्</td></tr><tr><td>चतुर्थी</td><td>खलप्वे</td><td>खलपूभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>खलप्वस्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>खलप्वोस्</td><td>खलप्वाम्</td><td></td></tr><tr><td>सप्तमी</td><td>खलप्वि</td><td>खलपूषु</td><td></td></tr></tbody></table></blockquote><p><img src="'+i+'" alt=""><br> Abb.: रथ्याप्वः<br> काशीपुर<br> [Bildquelle: Sumit. -- <a href="http://www.flickr.com/photos/sumit/107861850/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/sumit/107861850/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]]</p><h3 id="_61-1-6-deklination-mehrsilbiger-feminina-auf-u" tabindex="-1">61.1.6. Deklination mehrsilbiger Feminina auf -ū <a class="header-anchor" href="#_61-1-6-deklination-mehrsilbiger-feminina-auf-u" aria-label="Permalink to &quot;61.1.6. Deklination mehrsilbiger Feminina auf -ū&quot;">​</a></h3><p>Mehrsilbige Feminina auf -ū werden analog zu mehrsilbigen Stämmen auf -ī (देवी) dekliniert, sie enden aber im Nom. sg. auf -s.</p><p>Paradigma:</p><p>वधू f. &quot;junge Frau, Braut&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>वधूस्</td><td>वध्वौ</td><td>वध्वस्</td></tr><tr><td>द्वितीया</td><td>वधूम्</td><td>वधूस्</td><td></td></tr><tr><td>तृतीया</td><td>वध्वा</td><td>वधूभ्याम्</td><td>वधूभिस्</td></tr><tr><td>चतुर्थी</td><td>वध्वै</td><td>वधूभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>वध्वास्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>वध्वोस्</td><td>वधूनाम्</td><td></td></tr><tr><td>सप्तमी</td><td>वध्वाम्</td><td>वधूषु</td><td></td></tr><tr><td>आमन्त्रितम्</td><td>वधु</td><td>वध्वौ</td><td>वध्वस्</td></tr></tbody></table></blockquote><p><img src="'+o+'" alt=""><br> Abb.: वध्वौ<br> जोधपुर<br> [Bildquelle: thebigdurian. -- <a href="http://www.flickr.com/photos/thebigdurian/2200364164/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/thebigdurian/2200364164/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h2 id="_61-2-das-periphrastische-futur-लुट्" tabindex="-1">61.2. Das periphrastische Futur (लुट्) <a class="header-anchor" href="#_61-2-das-periphrastische-futur-लुट्" aria-label="Permalink to &quot;61.2. Das periphrastische Futur (लुट्)&quot;">​</a></h2><p>Neben dem einfachen Futur (ऌत्) gibt es ein periphrastisches Futur (लुट्). Nach der Lehre der einheimischen Grammatiker wird es verwendet, um die entfernte Zukunft (&quot;nach dem laufenden Tag&quot;) zu bezeichnen, während das einfache Futur die nahe Zukunft (&quot;am laufenden Tag&quot;) bezeichnet. Im klassischen Sanskrit scheint meist kein Unterschied im Gebrauch der beiden Futura gemacht zu werden.</p><p>Bildung:</p><p>Das periphrastische Futur wird gebildet durch die Verbindung eines nomen agentis auf -tṛ mit dem Präsens von अस् 2. Als dritte Person dient das einfache Nomen in der entsprechenden Zahl, ohne Unterscheidung im grammatischen Geschlecht. Bei den Verbindungen mit अस् hat das Nomen in allen Personen und Numeri die Form des Nom.sg. auf -tā.</p><p>Die Endungen des periphrastischen Futur lauten also:</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>द्विवचनम्</td></tr><tr><td>1. तृतीयः</td><td>-tāsmi</td><td></td></tr><tr><td>(-tā + asmi)</td><td>-tāsvas</td><td>-tāsmas</td></tr><tr><td>(-tā smas)</td><td>-tāhe</td><td>-tāsvahe</td></tr><tr><td>2. मध्यमः</td><td>-tāsi</td><td>-tāsthas</td></tr><tr><td>3. प्रथमः</td><td>-tā</td><td>-tārau</td></tr></tbody></table><p>Form der Wurzel: Die Wurzel hat im allgemeinen dieselbe Form wie im einfachen Futur. Dasselbe gilt für den Bindevokal -i-.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>दा 3U</th><th>दातास्मि, दतासि, दाता usw.</th></tr></thead><tbody><tr><td>भू 1P</td><td>भवितास्मि ... भाविता usw.</td></tr><tr><td>तुद् 6U</td><td>तोत्तास्मि ... तोत्ता usw.</td></tr><tr><td>गै 1P</td><td>गातास्मि ... गाता usw.</td></tr></tbody></table></blockquote><p>Paradigma:</p><p>दा 3U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>द्विवचनम्</td></tr><tr><td>1. तृतीयः</td><td>दातास्मि</td><td>दातास्वस्</td></tr><tr><td>2. मध्यमः</td><td>दातासि</td><td>दातास्थस्</td></tr><tr><td>3. प्रथम&gt;</td><td>दाता</td><td>दातारौ</td></tr></tbody></table></blockquote><p>Nur ganz selten wird das Verb अस् vom Nominalstamm getrennt.</p><h2 id="_61-3-das-intensivum-frequentativum-चर्करीतम्" tabindex="-1">61.3. Das Intensivum (Frequentativum) (चर्करीतम्) <a class="header-anchor" href="#_61-3-das-intensivum-frequentativum-चर्करीतम्" aria-label="Permalink to &quot;61.3. Das Intensivum (Frequentativum) (चर्करीतम्)&quot;">​</a></h2><p>Von jeder einsilbigen, konsonantisch anlautenden Wurzel der ersten neun Präsensklassen kan ein Intensivum (चर्करीतम्)  gebildet werden; das heißt: mit wenigen Ausnahmen kann von zweisilbigen Wurzeln (z.B. जागृ), vokalisch anlautenden Wurzeln und Wurzeln der 10. Präsensklasse (चुरादिगण) kein Intensivum gebildet werden.</p><p>Das Intensivum bedeutet:</p><ul><li>dass eine Person oder Sache immer wieder tut oder erleidet, was durch die Wurzel ausgedrückt wird<br> कृ 8U: चेक्रीयते / चर्करीति &quot;er tut immer wieder&quot;<br> भू 1P: बोभूयते / बोभवीति &quot;er ist (wird) oft&quot;</li><li>dass eine Person oder Sache intensiv tut oder erleidet, was durch die Wurzel ausgedrückt wird:<br> कृ 8U: चेक्रीयते / चर्करीति &quot;er tut intensiv, er tut tüchtig&quot;</li><li>bei Wurzeln, die eine Bewegung ausdrücken, bedeutet das Intensivum die gekrümmte Bewegung:<br> व्रज् 1P:  वव्रज्यते &quot;er geht in Krümmungen&quot; (NICHT: &quot;er geht oft&quot;)</li><li>bei einigen Wurzeln (Aufzählung: Kielhorn, Grammatik § 458b) bedeutet das Intensivum Tadel:<br> लुप् 6U: लोलुप्यते &quot;er schneidet schlecht&quot;<br> सद् 1P: सासद्यते &quot;er setzt sich schlecht&quot;</li></ul><p><img src="'+l+'" alt=""><br> Abb.: सर्पो वव्रज्यते ॥<br> Karnataka = ಕರ್ನಾಟಕ<br> [Bildquelle: Jessica Rabbit&#39;s Flickr. -- <a href="http://www.flickr.com/photos/jessicarabbit/179116811/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jessicarabbit/179116811/</a>. -- Zugriff am 2009-03-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Bildung des Intensivums:</p><p>Es gibt zwei Bildungstypen des Intensivums:</p><ul><li>Ātmanepada-Intensivum</li><li>Parasmaipada-Intensivum</li></ul><p>Beide werden von der mit starker Reduplikation reduplizierten Wurzel gebildet. Beide unterscheiden sich in der Bedeutung nicht. Beide können zu denselben Wurzeln gebildet werden.</p><h3 id="_61-3-1-atmanepada-intensivum" tabindex="-1">61.3.1. Ātmanepada-Intensivum <a class="header-anchor" href="#_61-3-1-atmanepada-intensivum" aria-label="Permalink to &quot;61.3.1. Ātmanepada-Intensivum&quot;">​</a></h3><p>Bildung:</p><p>reduplizierte Wurzel + -ya-</p><p>Form der Wurzel: im allgemeinen wie im Passiv, d.h. meist tiefstufig:</p><p>Beispiele:</p><blockquote><p>स्वप् 2P: Pass. सुप्यते ; Intens. सोषुप्यते<br> दा 3U: Pass. दीयते ; Intens. देदीयते</p></blockquote><p>Die Regeln im einzelnen bei Kielhorn, Grammatik § 461.</p><p>Reduplikation: nach den allgemeinen Regeln. Reduplikationsvokal aber: statt a,i,u steht ā, e, o</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>दा 3U</th><th>देदीय-</th></tr></thead><tbody><tr><td>भू 1P</td><td>बोभूय-</td></tr><tr><td>कृ 8U</td><td>चेक्रीय-</td></tr><tr><td>जीव् 1P</td><td>जेजीव्य-</td></tr><tr><td>शास् 2P</td><td>शेशिष्य-</td></tr><tr><td>ज्ञा 9U</td><td>जाज्ञाय-</td></tr></tbody></table></blockquote><p>Wurzeln der Form -a-Nasal verlängern in der Reduplikationssilbe den Vokal nicht, sondern wiederholen den Nasal.</p><blockquote><p>z.B. यम् 1P: यंयम्य-</p></blockquote><p>Bei einigen Wurzeln tritt zwischen den Vokal der Reduplikationssilbe und den anlautenden Konsonanten der Wurzel -nī- bzw. -rī- (-rī- bei Wurzeln, die im Intensiv ein ṛ enthalten).</p><blockquote><p>z.B.<br> पत् 1P: पनीपत्य-<br> वृत् 1Ā: वरीवृत्य-</p></blockquote><p>Konjugation:</p><ul><li>Präsensstamm: wie ein Ātmanepada der 4. Präsensklasse (दिवादिगण).</li><li>Passiv und übrige Tempusstämme: geht dem -ya- des Intensivstammes ein Vokal voraus, so wird das -ya- durch -y- ersetzt, geht dem -ya- ein Konsonant voraus, so entfällt das -ya-: <ul><li>Passiv Präsens: बुध् : बोबुध्यते ; भू : बोभूय्यते</li><li>Perfekt: periphrastisch:  बोबुधाञ्चक्रे ; बोभूयाञ्चक्रे</li><li>Aorist: iṣ-Aorist (Aorist 5): अबोबुधिष्ट ; अबोभूयिष्ट</li><li>Futur: seṭ: बोबुधिष्यते ; बोभूयिष्यते</li><li>periphrastisches Futur: बोबुधिता ; बोभूयिता</li></ul></li></ul><h3 id="_61-3-2-parasmaipada-intensivum" tabindex="-1">61.3.2. Parasmaipada-Intensivum <a class="header-anchor" href="#_61-3-2-parasmaipada-intensivum" aria-label="Permalink to &quot;61.3.2. Parasmaipada-Intensivum&quot;">​</a></h3><p>Präsensstamm (andere Formen sind äußerst selten): Bildung und Konjugation wie ein Verb der 3. Präsensklasse (जुहोत्यादिगण) mit dem Unterschied, dass der Vokal der Reduplikationssilbe hochstufig, bei -a- dehnstufig ist.</p><p>Im Singular Indikativ Präsens sowie 2.3.sg. Imperfekt und 3.sg.Imperativ kann zwischen Wurzel und Endung ein -ī- eingeschoben werden. Wird dieses -ī- eingeschoben, darf ein kurzer Vokal an vorletzter Stelle nicht guṇiert werden.</p><p>Bezüglich der Reduplikation mit Nasal sowie der Einschiebung von -nī- bzw. -rī- gilt dasselbe wie für das Ātmanepada-Intensivum. Statt -rī- kann wahlweise -ri- stehen.</p><p>Paradigma:</p><p>भू 1P</p><p>Indikativ Präsens (लट्):</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>बोभोमि । बोभवीमि</td><td>बोभूवस्</td><td>बोभूमस्</td></tr><tr><td>2. मध्यमः</td><td>बोभोषि । बोभवीषि</td><td>बोभूथस्</td><td>बोभूथ</td></tr><tr><td>3. प्रथमः</td><td>बोभोति । बोभवीति</td><td>बोभूतस्</td><td>बोभुवति</td></tr></tbody></table></blockquote><p>Imperfekt (लङ्):</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>अबोभवम्</td><td>अबोभूव</td><td>अबिभूम</td></tr><tr><td>2. मध्यमः</td><td>अबोभोस् । अबोभवीस्</td><td>अबोभूतम्</td><td>अबोभूत</td></tr><tr><td>3. प्रथमः</td><td>अबोभोत् । अबोभवीत्</td><td>अबोभूताम्</td><td>अबोभुवुर्</td></tr></tbody></table></blockquote><p>Imperativ (लोट्):</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>बोभवानि</td><td>बोभवाव</td><td>बोभवाम</td></tr><tr><td>2. मध्यमः</td><td>बोभूहि</td><td>बोभूतम्</td><td>बोभूत</td></tr><tr><td>3. प्रथमः</td><td>बोभोतु । बोभवितु</td><td>बोभूताम्</td><td>बोभुवतु</td></tr></tbody></table></blockquote><p>Optativ (विधिलिङ्):</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>बोभूयाम्</td><td>बोभूयाव</td><td>बोभूयाम</td></tr><tr><td>2. मध्यमः</td><td>बोभूयास्</td><td>बोभूयातम्</td><td>बोभूयात</td></tr><tr><td>3. प्रथमः</td><td>बोभूयात्</td><td>बोभूयाताम्</td><td>बोभूयुर्</td></tr></tbody></table></blockquote><h2 id="_61-4-denominativa-नामधातु" tabindex="-1">61.4. Denominativa (नामधातु) <a class="header-anchor" href="#_61-4-denominativa-नामधातु" aria-label="Permalink to &quot;61.4. Denominativa (नामधातु)&quot;">​</a></h2><p>Denominativa (नामधातवः) werden, im Gegensatz zu den bisher behandelten Verben, nicht von einer Verbalwurzel, sondern von einem Nominalstamm gebildet. Dabei gibt es verschiedene Bildungstypen.</p><h3 id="_61-4-1-bildung-ohne-besonderes-suffix-parasmaipada" tabindex="-1">61.4.1. Bildung ohne besonderes Suffix, Parasmaipada <a class="header-anchor" href="#_61-4-1-bildung-ohne-besonderes-suffix-parasmaipada" aria-label="Permalink to &quot;61.4.1. Bildung ohne besonderes Suffix, Parasmaipada&quot;">​</a></h3><p>Bedeutung:</p><blockquote><p>eine Person oder Sache verhält sich so wie das, oder gleicht dem, was vom Nominalstamm bezeichnet wird.</p></blockquote><p>Konjugation:</p><blockquote><p>im Präsensstamm wie ein Verb der 1. Präsensklasse (भ्वादिगण). Hat das Nomen mehl als einen vokal, so wird nur der letzte Vokal wie der Wurzelvokal der 1. Klasse behandelt. Auslautendes -a entfällt vor dem Themavokal. Vokal vor auslautendem Nasal wird durch den entsprechenden Langvokal ersetzt.</p></blockquote><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>कवि m. &quot;Dichter&quot;</th><th>कवयति &quot;er verhält sich wie ein Dichter&quot;</th></tr></thead><tbody><tr><td>भू f. &quot;Erde&quot;</td><td>भवति &quot;er verhält sich wie die Erde&quot;</td></tr><tr><td>पितृ &quot;Vater&quot;</td><td>पितरति &quot;er verhält sich wie ein Vater&quot;</td></tr><tr><td>कृष्ण m. Kṛṣṇa</td><td>कृष्णति &quot;er verhält sich wie Kṛṣṇa&quot;</td></tr><tr><td>माला f. &quot;Kranz&quot;</td><td>मालाति &quot;es gleicht einem Kranz&quot;</td></tr><tr><td>राजन् m. &quot;König&quot;</td><td>राजानति &quot;er verhält sich wie ein König&quot;</td></tr></tbody></table></blockquote><h3 id="_61-4-2-bildung-mit-suffix-ya-parasmaipada" tabindex="-1">61.4.2. Bildung mit Suffix -ya, Parasmaipada <a class="header-anchor" href="#_61-4-2-bildung-mit-suffix-ya-parasmaipada" aria-label="Permalink to &quot;61.4.2. Bildung mit Suffix -ya, Parasmaipada&quot;">​</a></h3><p>Bedeutung:</p><ul><li>jemand wünscht sich das, was durch den Nominalstamm bezeichnet wird</li><li>jemand behandelt oder betrachtet eine Person oder Sache wie das, was vom Nominalstamm bezeichnet wird</li></ul><p>Stammbildung:</p><blockquote><p>vor dem -ya unterliegt der Auslauts des Nominalstamms folgenden Veränderungen:</p><ul><li>a, ā » ī : पुत्र » पुत्रीय-</li><li>i, u  » ī, ū : कवि » कवीय-</li><li>ṛ » rī : कर्तृ » कर्त्रीय-</li><li>o » av : गो » गव्य-</li><li>au » āv : नौ » नाव्य-</li><li>auslautender Nasal fällt ab, davor stehender Vokal wird nach den eben genannten Regeln behandelt: राजन् » राजीय-</li><li>andere auslautende Konsonanten bleiben unverändert</li></ul></blockquote><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>पुत्र m. &quot;Sohn&quot;</th><th>पुत्रीयति &quot;er wünscht sich einen Sohn&quot;</th></tr></thead><tbody><tr><td>कवि m. &quot;Dichter&quot;</td><td>कवीयति &quot;er wünscht sich einen Dichter&quot;</td></tr><tr><td>गो f. &quot;Kuh&quot;</td><td>गव्यति &quot;er wünscht sich eine Kuh&quot;</td></tr><tr><td>राजन् m. &quot;König&quot;</td><td>राजीयति &quot;er wünscht sich einen König&quot;</td></tr><tr><td>विष्णु m. Viṣṇu</td><td>विष्णूयति &quot;er behandelt jemanden wie Viṣṇu&quot;</td></tr><tr><td>प्रासाद m. &quot;Palast&quot;</td><td>प्रासादीयति &quot;er sieht (z.B. seine Hütte) für einen Palast an&quot;</td></tr></tbody></table></blockquote><p>Beachten sie die Bedeutung von:</p><blockquote><table tabindex="0"><thead><tr><th>तपस् n. &quot;Askese&quot;</th><th>तपस्यति &quot;er übt Askese&quot;</th></tr></thead><tbody><tr><td>नमस् n. &quot;Verehrung&quot;</td><td>नमस्यति &quot;er verehrt&quot;</td></tr></tbody></table></blockquote><p><img src="'+u+'" alt=""><br> Abb.: किं तपस्यति न वा ?<br> हरिद्वार<br> [Bildquelle: Naresh Dhiman. -- <a href="http://www.flickr.com/photos/nareshdhiman/311832594/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/nareshdhiman/311832594/</a>. -- Zugriff am 2009-03-08. --  <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p><img src="'+s+'" alt=""><br> Abb.: बालौ शिवं नमस्यतः ॥<br> [Bildquelle: frisse82. -- <a href="http://www.flickr.com/photos/frisse82/496195924/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/frisse82/496195924/</a>. -- Zugriff am 2009-03-08. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><h3 id="_61-4-3-bildung-mit-dem-suffix-kamya-parasmaipada" tabindex="-1">61.4.3. Bildung mit dem Suffix -kāmya, Parasmaipada <a class="header-anchor" href="#_61-4-3-bildung-mit-dem-suffix-kamya-parasmaipada" aria-label="Permalink to &quot;61.4.3. Bildung mit dem Suffix -kāmya, Parasmaipada&quot;">​</a></h3><p>Bedeutung:</p><blockquote><p>jemand wünsch sich das, was durch den Nominalstamm bezeichnet wird</p></blockquote><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>पुत्र m. &quot;Sohn&quot;</th><th>पुत्रकाय्म्यति &quot;er wünscht sich einen Sohn&quot;</th></tr></thead><tbody><tr><td>यशस् n. &quot;Ruhm&quot;</td><td>यशस्काम्यति &quot;er wünscht sich Ruhm&quot;</td></tr></tbody></table></blockquote><p><img src="'+h+'" alt=""><br> Abb.: यशस्काम्यन्ति<br> मुंबई<br> [Bildquelle: FrogStarB. -- <a href="http://www.flickr.com/photos/wormtongue/237776303/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wormtongue/237776303/</a>. --- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h3 id="_61-4-4-bildung-mit-dem-suffix-sya-oder-asya-parasmaipada" tabindex="-1">61.4.4. Bildung mit dem Suffix -sya oder -asya, Parasmaipada <a class="header-anchor" href="#_61-4-4-bildung-mit-dem-suffix-sya-oder-asya-parasmaipada" aria-label="Permalink to &quot;61.4.4. Bildung mit dem Suffix -sya oder -asya, Parasmaipada&quot;">​</a></h3><p>Bedeutung:</p><blockquote><p>jemand verlangt heftig nach dem, was durch den Nominalstamm bezeichnet wird.</p></blockquote><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>मधु n. &quot;Honig&quot;</th><th>मधुस्यति । मध्वस्यति &quot;er verlangt heftig nach Honig&quot;</th></tr></thead><tbody><tr><td>अश्व m. &quot;Hengst&quot;</td><td>अश्वस्यति &quot;(die Stute) verlangt heftig nach dem Hengst&quot;</td></tr></tbody></table></blockquote><p><img src="'+m+'" alt=""><br> Abb.: कस्तत्र न मधुस्यति ?<br> Karli<br> [Bildquelle: Makwa. -- <a href="http://www.flickr.com/photos/makwa/140499307/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/makwa/140499307/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h3 id="_61-4-5-bildung-mit-dem-suffix-ya-atmanepada" tabindex="-1">61.4.5. Bildung mit dem Suffix -ya, Ātmanepada <a class="header-anchor" href="#_61-4-5-bildung-mit-dem-suffix-ya-atmanepada" aria-label="Permalink to &quot;61.4.5. Bildung mit dem Suffix -ya, Ātmanepada&quot;">​</a></h3><p>Bedeutung:</p><blockquote><p>jemand verhält sich als das, oder gleicht dem, was durch den Nominalstamm bezeichnet wird.</p></blockquote><p>Bildung:</p><ul><li>auslautendes -a » -ā</li><li>auslautendes -ā bleibt unverändert</li><li>sonst wie vor -ya, Parasmaipada (siehe oben 4.2.)</li><li>auslautendes -as wahlweise » -ā</li><li>Femininstamm meist » Maskulinstamm</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>कृष्ण m. Kṛṣṇa</th><th>कृष्णायते &quot;er verhält sich wie Kṛṣṇa</th></tr></thead><tbody><tr><td>यशस् 3 &quot;berühmt&quot;</td><td>यशायते । यशस्यते &quot;er verhält sich wie ein Berühmter&quot;</td></tr><tr><td>कुमारी f. &quot;Mädchen&quot;</td><td>कुमारायते &quot;er verhält sich wie ein Mädchen&quot;</td></tr></tbody></table></blockquote><p>Bei einigen Nominalstämmen bedeutet dieses Suffix: etwas wird wie das, oder wird zu dem, was durch den Nominalstamm bezeichnet wird:</p><blockquote><p>z.B. उन्मनस् 3 &quot;erregt&quot;: उन्मनायते &quot;er wird erregt&quot;</p></blockquote><p>In einigen Fällen werden mit diesem Suffix Verben in anderen Bedeutungen gebildet:</p><p>Beispiele:</p><blockquote><p>दुःख n. &quot;Leid&quot; : दुःखायते &quot;er empfindet Leid&quot;<br> शब्द m. &quot;Laut&quot; : शब्दायते &quot;er gibt einen Ton von sich&quot;</p></blockquote><p><img src="'+b+'" alt=""><br> Abb.: श्वानौ शब्दायेते<br> [Bildquelle: technicolorcavalry. -- <a href="http://www.flickr.com/photos/technicolorcavalry/155364212/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/technicolorcavalry/155364212/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><h3 id="_61-4-6-bildung-mit-dem-suffix-aya-apaya" tabindex="-1">61.4.6. Bildung mit dem Suffix -aya, -āpaya <a class="header-anchor" href="#_61-4-6-bildung-mit-dem-suffix-aya-apaya" aria-label="Permalink to &quot;61.4.6. Bildung mit dem Suffix -aya, -āpaya&quot;">​</a></h3><p>Verschiedene Bedeutungen.</p><p>Konjugiert wie Kausativa.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>सत्य 3 &quot;wahr&quot;</th><th>स्तयपायति &quot;er erklärt für wahr&quot;</th></tr></thead><tbody><tr><td>मुण्ड 3 &quot;kahlgeschoren&quot;</td><td>मुण्डयति &quot;er schert kahl&quot;</td></tr></tbody></table></blockquote><p><img src="'+p+'" alt=""><br> Abb.: भिक्षुर्मुण्डयते ।<br> Thailand - เมืองไทย<br> [Bildquelle: Sailing &quot;Footprints: Real to Reel&quot; (Ronn ashore). -- <a href="http://www.flickr.com/photos/12392252@N03/2505961590/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/12392252@N03/2505961590/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Eine Liste von Denominative z.B. in:</p><p><img src="'+c+'" alt=""><br> Abb.: Niels Ludvig Westergaard (1815 - 1878)<br> 1845 - 1878 Professor der indisch-orientalischen Philologie an der Universität Kopenhagen</p><blockquote><p><strong>Westergaard</strong>, Niels Ludvig &lt;1815-1878&gt;: Radices linguae Sanscritae ad decreta grammaticorum definivit atque copia exemplorum exquisitiorum illustravit / N. L. Westergaard. -- Bonnae ad Rhenum : König, 1841. -- S. 335 - 341.</p></blockquote><h2 id="_61-5-der-benediktiv-आशीर्लिङ्" tabindex="-1">61.5. Der Benediktiv (आशीर्लिङ्) <a class="header-anchor" href="#_61-5-der-benediktiv-आशीर्लिङ्" aria-label="Permalink to &quot;61.5. Der Benediktiv (आशीर्लिङ्)&quot;">​</a></h2><p>Bedeutung:</p><blockquote><p>Segenswunsch</p></blockquote><p>Bildung:</p><p>Parasmaipada:</p><p>tiefstufige Wurzel + yās + Sekundärendung</p><blockquote><p>z.B. बुध्यासम् &quot;möge ich erkennen!&quot;</p></blockquote><p>Ātmanepada:</p><p>(meist) hochstufige Wurzel + sī(y) + Sekundärendung</p><p>oder:</p><p>(hochstufige) Wurzel + ै + sī(y) + Sekundäraendung</p><blockquote><p>z.B.<br> जि : जेषीय &quot;möge ich im eigenen Interesse siegen!&quot;<br> बुध् : बोधिषीय &quot;möge ich erkennen&quot;</p></blockquote><p>Die Regeln zur Form der Wurzel im Einzelnen bei Kielhorn, Grammatik § 380ff.</p><p>Paradigma:</p><p>बुध् &quot;erwachen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>द्विवचनम्</td></tr><tr><td>1. तृतीयः</td><td>बुध्यासम्</td><td>बुध्यास्व</td></tr><tr><td>2. मध्यमः</td><td>बुध्यास्</td><td>बुध्यास्तम्</td></tr><tr><td>3. प्रथमः</td><td>बुध्यात्</td><td>बुध्यास्ताम्</td></tr></tbody></table></blockquote><p><img src="'+g+'" alt=""><br> Abb.: नववर्षं शुभं भूयात् ॥<br> Santa Cruz Basilica, Kochi = കൊച്ചി<br> [Bildquelle: monsieur paradis. -- <a href="http://www.flickr.com/photos/zacharyparadis/3189670791/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/zacharyparadis/3189670791/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><h2 id="_61-6-der-konditionalis-ऌङ्" tabindex="-1">61.6. Der Konditionalis (ऌङ्) <a class="header-anchor" href="#_61-6-der-konditionalis-ऌङ्" aria-label="Permalink to &quot;61.6. Der Konditionalis (ऌङ्)&quot;">​</a></h2><p>Der Konditionalis (ऌङ्) wird verwendet, wenn man in Bedingungssätzen ausdrücken will, dass das, was als Bedingung genannt wird, nicht der Fall ist / gewesen ist / sein wird. Der Konditionalis muss bei solchen Sätzen sowohl im Bedingungssatz wie im Hauptsatz verwendet werden.</p><p>Beispiel:</p><blockquote><p>सुवृष्टिश्चेदभविष्यत्सुभिक्षमभविष्यत् &quot;Wenn es gut geregnet hätte (oder regnen würde), würde es trreichlich Nahrung geben. (Es hat aber nicht (genügend) geregnet.)&quot;</p></blockquote><p>Bildung des Konditionalis (ऌङ्):</p><p>Augment + Stamm des einfachen Futur (ऌत्) + Sekundärendung</p><p>d.h. wie ein Imperfekt (लङ्) zum Futurstamm.</p><p>z.B. अदास्यम् ; अभविष्यम् ; अतोत्स्यम्</p><p>Paradigma:</p><p>भू &quot;sein, werden&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>द्विवचनम्</td></tr><tr><td>1. तृतीयः</td><td>अभविष्यम्</td><td>अभविष्याव</td></tr><tr><td>2. मध्यमः</td><td>अभविष्यस्</td><td>अभविष्यतम्</td></tr><tr><td>3. प्रथमः</td><td>अभविष्यत्</td><td>अभविष्यताम्</td></tr></tbody></table></blockquote><h2 id="_61-7-deklination-der-nomina-auf-ai-o-au" tabindex="-1">61.7. Deklination der Nomina auf -ai, -o, -au <a class="header-anchor" href="#_61-7-deklination-der-nomina-auf-ai-o-au" aria-label="Permalink to &quot;61.7. Deklination der Nomina auf -ai, -o, -au&quot;">​</a></h2><p>Vor Konsonant lauten diese Stämme auf -ai, -o, -au; vor Konsonant auf -āy, -av, -āv</p><p>गो m.f. &quot;Ochse, Kuh&quot; hat Stammabstufung. Siehe die Erklärung im Einzelnen bei Thumb-Hauschild § 296/7.</p><p>Paradigmen: Kielhorn, Grammatik § 153:</p><p><img src="'+k+'" alt=""></p><p><img src="'+f+'" alt=""><br> Abb.: हरिद्वारे गावः ॥<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/2086490984/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/2086490984/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><h2 id="_61-8-restliche-pronomina" tabindex="-1">61.8. Restliche Pronomina <a class="header-anchor" href="#_61-8-restliche-pronomina" aria-label="Permalink to &quot;61.8. Restliche Pronomina&quot;">​</a></h2><h3 id="_61-8-1-personalpronomen-des-dual" tabindex="-1">61.8.1. Personalpronomen des Dual <a class="header-anchor" href="#_61-8-1-personalpronomen-des-dual" aria-label="Permalink to &quot;61.8.1. Personalpronomen des Dual&quot;">​</a></h3><p>Kielhorn, Grammatik § 177:</p><p><img src="'+q+'" alt=""></p><p><img src="'+w+'" alt=""><br> Abb.: आवां स्वसारौ ॥<br> Apatani-Volk, Arunachal Pradesh<br> [Bildquelle: ahinsajain. -- <a href="http://www.flickr.com/photos/ahinsajain/3165501187/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ahinsajain/3165501187/</a>. -- Zugriff am 2009-03-09. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><h3 id="_61-8-2-demonstrativpronomen-अदस्-jener-entfernte" tabindex="-1">61.8.2. Demonstrativpronomen अदस् &quot;jener (entfernte)&quot; <a class="header-anchor" href="#_61-8-2-demonstrativpronomen-अदस्-jener-entfernte" aria-label="Permalink to &quot;61.8.2. Demonstrativpronomen अदस् &quot;jener (entfernte)&quot;&quot;">​</a></h3><p>Maskulinum (पुंस्)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>असौ</td><td>अमू</td><td>अमी</td></tr><tr><td>द्वितीया</td><td>अमुम्</td><td>अमून्</td><td></td></tr><tr><td>तृतीया</td><td>अमुना</td><td>अमूभ्याम्</td><td>अमीभिस्</td></tr><tr><td>चतुर्थी</td><td>अमुष्मै</td><td>अमीभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>अमुष्मात्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>अमुष्य</td><td>अमुयोस्</td><td>अमीषाम्</td></tr><tr><td>सप्तमी</td><td>अमुष्मिन्</td><td>अमीषु</td><td></td></tr></tbody></table></blockquote><p>Neutrum (नपुंसक)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>अदस्</td><td>अमू</td><td>अमूनि</td></tr><tr><td>द्वितीया</td><td></td><td></td><td></td></tr></tbody></table><p>Rest wie Maskulinum</p></blockquote><p>Femininum (स्त्री)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>असौ</td><td>अमू</td><td>अमूस्</td></tr><tr><td>द्वितीया</td><td>अमूम्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>अमुना</td><td>अमूभ्याम्</td><td>अमूभिस्</td></tr><tr><td>चतुर्थी</td><td>अमुष्यै</td><td>अमूभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>अमुष्यास्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>अमुयोस्</td><td>अमूषाम्</td><td></td></tr><tr><td>सप्तमी</td><td>अमुष्याम्</td><td>अमूषु</td><td></td></tr></tbody></table></blockquote><h2 id="_61-9-entlassung-in-den-ozean-der-sanskritliteratur-ಶ್ರೀಗಣನಾಥ-श्रीगणनाथ" tabindex="-1">61.9. Entlassung in den Ozean der Sanskritliteratur: ಶ್ರೀಗಣನಾಥ / श्रीगणनाथ <a class="header-anchor" href="#_61-9-entlassung-in-den-ozean-der-sanskritliteratur-ಶ್ರೀಗಣನಾಥ-श्रीगणनाथ" aria-label="Permalink to &quot;61.9. Entlassung in den Ozean der Sanskritliteratur: ಶ್ರೀಗಣನಾಥ / श्रीगणनाथ&quot;">​</a></h2><p>Nach dem Abschluss des Sanskritkurses beginnt erst das eigentliche &quot;Schwimmen&quot; im Ozean der Sanskritliteratur. Da dieser Ozean voller Hindernisse ist, ist es angemessen, diesen neuen Lebensabschnitt mit einer Anrufung Gaṇeśas zu beginnen:</p><p><img src="'+v+'" alt=""><br> Abb.: श्रीगणनाथः<br> Halebidu (ಹಳೆಬೀಡು), 12./13. Jhdt. n. Chr.<br> [Bildquelle: Quadell / Wikipedia. GNU FDLicense]</p><table><tbody><tr><td>ಶ್ರೀಗಣನಾಥ ಸಿನ್ಧುರವರ್ಣ<br>ಕರುಣಾಸಾಗರ ಕರಿವದನ&lt;blockquote&gt;ಲಮ್ಬೋದರ ಲಕುಮೀಕರ<br>ಅಮ್ಬಾಸುತ ಅಮರವಿನುತ<br>ಲಮ್ಬೋದರ ಲಕುಮೀಕರ<br>&lt;/blockquote&gt;ಸಿದ್ಧಚಾರಣ ಗಣಸೇವಿತ<br>ಸಿದ್ಧಿವಿನಾಯಕ ತೇ ನಮೋ ನಮೋ<br>&lt;blockquote&gt;ಲಮ್ಬೋದರ ಲಕುಮೀಕರ<br>ಅಮ್ಬಾಸುತ ಅಮರವಿನುತ<br>ಲಮ್ಬೋದರ ಲಕುಮೀಕರ<br>&lt;/blockquote&gt;ಸಕಲವಿದ್ಯಾದಿಪೂಜಿತ<br>ಸರ್ವೋತ್ತಮ ತೇ ನಮೋ ನಮೋ<br>&lt;blockquote&gt;ಲಮ್ಬೋದರ ಲಕುಮೀಕರ<br>ಅಮ್ಬಾಸುತ ಅಮರವಿನುತ<br>ಲಮ್ಬೋದರ ಲಕುಮೀಕರ<br>&lt;/blockquote&gt;</td><td>श्रीगणनाथ सिन्धुरवर्ण<br>करुणासागर करिवदन&lt;blockquote&gt;लम्बोदर लकुमीकर<br>अम्बासुत अमरविनुत<br>लम्बोदर लकुमीकर <sup>१</sup><br>&lt;/blockquote&gt;सिद्धचारण गणसेवित<br>सिद्धिविनायक ते नमो नमो<br>&lt;blockquote&gt;लम्बोदर लकुमीकर<br>अम्बासुत अमरविनुत<br>लम्बोदर लकुमीकर<br>&lt;/blockquote&gt;सकलविद्यादिपूजित<br>सर्वोत्तम ते नमो नमो<br>&lt;blockquote&gt;लम्बोदर लकुमीकर<br>अम्बासुत अमरविनुत<br>लम्बोदर लकुमीकर<br>&lt;/blockquote&gt;<sup>१</sup> लकुमीकर ≈ लक्ष्मीकर</td></tr><tr><td colspan="2">**ಶ್ರೀಗಣನಾಥ** / श्रीगणनाथ von Purandaradāsa (**ಪುರಂದರ ದಾಸ**) (1484 - 1564)</td></tr></tbody></table><p>Komponist und Dichter: Purandaradāsa (ಪುರಂದರ ದಾಸ) (1484 - 1564)</p><p>Rāga: Malahari (zu मायामाळवगौळ = Māyāmālavagauḷa = ಮಾಯಾಮಾಲವಗೌಳ = மாயாமாளவகௌளை):</p><ul><li><p>ārohaṇa: s r1 m1 p d1 S</p></li><li><p>avarohaṇa: S d1 p m1 g3 r1 s</p></li></ul><p>Tāla: Rūpaka: o |4</p><p><img src="'+z+'" alt=""><br> Abb.: Melodie, auf c bezogen, kann je nach Stimmlage transponiert werden.</p><p>ಶ್ರೀಗಣನಾಥ / श्रीगणनाथ steht am Beginn des Unterrichts in kannaresischer Musik. Siehe das Video: <a href="http://www.youtube.com/watch?v=tG91JF-qKIY" target="_blank" rel="noreferrer">http://www.youtube.com/watch?v=tG91JF-qKIY</a>. -- Zugriff am 2009-03-05</p><p>Nachdem Sie jetzt die Grundlagen des Sanskrit gelernt haben, sind Sie hoffentlich wie die Kleinkinder im Video: manchmal ungeschickt, aber lern- und wissensbegierig und mit Freude bei der Sache. Behalten Sie bis an Ihr Lebensende &quot;a beginner&#39;s mind&quot;.</p><p>Das wünscht Ihnen Ihr Alois Payer</p><p>Ofterdingen, 2009-03-09</p><p>ॐ</p><p>ENDE DES SANSKRITKURSES</p>',215)])])}const W=e(y,[["render",_]]);export{K as __pageData,W as default};
